import { useEffect, useState } from 'react';
import { importNamespace, translate } from '#modules/translation/translation.utils';
import { useLangContext } from '#modules/translation/translations.context';
import { Namespace, Namespaces, TranslationHook } from '#modules/translation/translations.types';

export const useTranslation = (namespaceNames: Namespaces[] = [Namespaces.COMMON]): TranslationHook => {
    const { lang } = useLangContext();

    const [namespaces, setNamespaces] = useState<Namespace[] | undefined>();

    const prepareNamespace = async () => {
        try {
            const promises = namespaceNames.map((namespaceName) => {
                return importNamespace(lang, namespaceName);
            });
            await Promise.all(promises).then((values) => {
                setNamespaces(values);
            });
        } catch (error) {
            console.error(error);
        }
    };

    useEffect(() => {
        prepareNamespace();
    }, [lang]);

    return {
        t: (key: string) => {
            return translate(lang, key, namespaces);
        },
    };
};
