import { Dispatch, SetStateAction } from 'react';

export enum Languages {
    LANG_FR = 'fr',
    LANG_EN = 'en',
}

export enum Namespaces {
    COMMON = 'common',
    TEST = 'test',
}

export interface LangContextState {
    lang: Languages;
    setLang: Dispatch<SetStateAction<Languages>>;
}

export type NamespaceObject = { [key: string]: string | NamespaceObject };

export type Namespace = { name: Namespaces; object: NamespaceObject };

export type NamespaceImport = { default: NamespaceObject };

export interface TranslationHook {
    t: TFunction;
}

export type TFunction = (key: string) => string;
