import { Languages, Namespace, NamespaceImport, NamespaceObject, Namespaces } from './translations.types';

export const updateLangQueryParam = (value: Languages): void => {
    const queryParams = new URLSearchParams(window.location.search);
    queryParams.set('lang', value);
    window.history.pushState(null, 'null', `?${queryParams.toString()}`);
};

export const getInitialLang = (): Languages => {
    const { LANG_FR, LANG_EN } = Languages;
    const queryParams = new URLSearchParams(window.location.search);
    const paramLang = queryParams.get('lang') as Languages;
    if ([LANG_EN, LANG_FR].includes(paramLang)) {
        return paramLang;
    }
    return LANG_FR;
};

export const importNamespace = async (lang: Languages, namespace: Namespaces): Promise<Namespace> => {
    const namespaceObject: NamespaceImport = await import(`./translationObjects/${lang}/${namespace}`);
    return { name: namespace, object: namespaceObject.default };
};

export const translate = (lang: Languages, keyPath: string, namespaces?: Namespace[]): string => {
    const splittedKeys = keyPath.split('.');
    if (!namespaces || !Array.isArray(namespaces) || namespaces.length < 1) return '';

    const translatedValues = namespaces.map((namespace) => {
        return splittedKeys.reduce((acc: NamespaceObject | string | undefined, splittedKey) => {
            if (typeof acc === 'object') return acc?.[splittedKey];
            return undefined;
        }, namespace.object);
    });

    const translatedValue = translatedValues.find((elt) => elt);

    if (typeof translatedValue === 'object') return `!!! The key ${lang}.${keyPath} is an object. String expected. !!!`;

    return translatedValue || `!!! The key ${lang}.${keyPath} doesn't exists !!!`;
};
